sp_widget.client_script:
function($rootScope, $scope, $timeout, spAriaFocusManager, $http, amb, spModal, $uibModal, $location, $log, $window, spUtil, spAriaUtil, spNavStateManager) {
	// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
	// Script Continued Below
	//------------------------------------------------------------------------------------------------------------------------
	// STRY0108629
	var c = this;
	$scope.submitting = false;
	$scope.mandatory = [];
	$scope.errorMessages = [];
	$scope.data.show_sql = false;
	$scope.saveButtonSuffix = spUtil.getAccelerator('s');
	$scope.isPageReady = false;
	$scope.adminMenu = {
		encodedPageUrl: encodeURIComponent($location.url()),
		getClientScriptCount: function() {
			var count = 0;
			if ($scope.data.f.client_script) {
				count += $scope.data.f.client_script.onChange.length;
				count += $scope.data.f.client_script.onLoad.length;
				count += $scope.data.f.client_script.onSubmit.length;
			}
			return count;
		}
	};

	var eventNames = {
		click: 'data_table.click',
		setFilter: 'data_table.setFilter',
		setKeywords: 'data_table.setKeywords',
		// STRY0108629
		loadItem: '$sp.list.click'
	};

	$rootScope.$on('$sp.html.editor.progress', function(e, conf) {
		$scope.submitting = conf.state;
	});

	$scope.set_sys_id = function(sys_id) {
		loadForm($scope.data.table, sys_id);
	};

	$scope.getButtonClass = function(action) {
		if (action.form_style == "destructive")
			return "btn-danger";

		if (action.form_style == "primary")
			return "btn-primary";

		return "btn-default";
	};

	$scope.getUIActions = function(type) {
		if ($scope.data.disableUIActions)
			return [];
		if (type) {
			return $scope.data.f._ui_actions.filter(function(action) {
				//We handle the primary action button separately.
				return !action.primary && action['is_' + type];
			});
		} else {
			return $scope.data.f._ui_actions;
		}
	}

	$scope.getPrimaryAction = function() {
		var primaryActions = $scope.data.f._ui_actions.filter(function(action) {
			return action.primary;
		});		
		return (primaryActions.length) ? primaryActions[0] : null;
	}

	$scope.getUIActionContextMenu = function(event) {
		var menu = [];
		if (event.ctrlKey)
			return menu;

		var contextActions = $scope.getUIActions('context');
		contextActions.forEach(function(action) {
			menu.push([action.name, function() {
				$scope.triggerUIAction(action);
			}]);
		});

		if (contextActions.length > 0)
			menu.push(null);
		menu.push([$scope.data.exportPDFMsg, function() {
			exportPDF("");
		}]);
		menu.push([$scope.data.exportPDFLandMsg, function() {
			exportPDF('true');
		}]);

		return menu;
	}

	function exportPDF(landscape) {
		$window.open("/" + $scope.data.f.table + ".do?PDF&landscape=" + landscape + "&sys_id=" + $scope.data.sys_id + "&sysparm_view=" + $scope.data.f.view);
	}

	//trigger the primary UI Action on save (if there is one)
	var deregister = $scope.$on('$sp.save', function() {
		var primaryAction = $scope.getPrimaryAction();
		if (primaryAction)
			$scope.triggerUIAction(primaryAction);
	});
	$scope.$on('$destroy', function() {
		deregister()
	});

	$scope.triggerUIAction = function(action) {
		if ($scope.data.disableUIActions && !action.primary) {
			return;
		}

		var activeElement = document.activeElement;
		if (activeElement) {
			activeElement.blur();
		}

		$scope.$evalAsync(function() {
			if (g_form) {
				$scope.submitting = true;
				if (!g_form.submit(action.action_name || action.sys_id))
					$scope.submitting = false;
			}
		});
	}

	$scope.$on("spModel.uiActionComplete", function(evt, response, savedFormSysId) {
		if ($scope.data.sys_id !== savedFormSysId)
			return;

		$scope.submitting = false;
		if (response.isActionAborted)
			return;

		// UI Action just completed move to the next item if it exists
		//    If no more next items, go to previous.  If now more previous show splash
		var sysID;
		if(savedFormSysId == $scope.data.sys_id  && c.data.nextRec.sys_id != ''){
			// move next
			sysID = c.data.nextRec.sys_id;
		} else if(savedFormSysId == $scope.data.sys_id  && c.data.prevRec.sys_id != '') {
			sysID = c.data.prevRec.sys_id;
		} else {
			// here is where we would load the landing page b/c there are no more requests to process
			sysID = -1;
		}
		$scope.set_sys_id(sysID);
	});

	function constructResponseHandler() {
		return function() {
			$rootScope.$broadcast("sp.form.submitted", {sys_id: $scope.data.sys_id});
			var message;
			var eventName = "sp.form.record.updated";
			message = $scope.data.updatedMsg;

			$scope.data.hideRelatedLists = hideRelatedLists();
			$scope.$emit(eventName, $scope.data.f._fields, $scope.data.sys_id);
			$rootScope.$broadcast(eventName, $scope.data.f._fields, $scope.data.sys_id);
			$scope.status = message;
			spUtil.addTrivialMessage(message);
			$timeout(clearStatus, 2000);
		}
	}

	var ctrl = this;

	$scope.$on("$destroy", function() {
		unregister();
	})

	function _save() {
		var primaryAction = $scope.getPrimaryAction();
		if (primaryAction)
			$scope.triggerUIAction(primaryAction);
	}

	function loadForm(table, sys_id) {
		var f = {};
		$scope.data.use_Discover_Controller_URL = c.data.use_Discover_Controller_URL;
		$scope.data.table = f.table = table;
		$scope.data.sys_id = f.sys_id = sys_id;
		$scope.data.view =	f.view = c.data.view;
		$scope.server.update().then(function(){
			$scope.go(c.data.send_table, c.data.send_sys_id)
		});
	}

	function openRelatedList(e, queryString) {
		// todo: Open this in a modal
		$location.search(queryString);
		e.preventDefault();
	}

	$scope.$on('spModel.fields.rendered', function() {
		if (ctrl.panels)
			ctrl.panels.removeClass('shift-out').addClass('shift-in');
	});

	var g_form;
	function initForm(gFormInstance) {
		if (gFormInstance.getTableName() == $scope.data.f.table){
			g_form = gFormInstance;
			spNavStateManager.register($scope.data.table, _save, g_form);
			$scope.isPageReady = true;
			$timeout(function() {
				$rootScope.$emit('spModel.gForm.rendered', g_form);
				if(c.data.use_Discover_Controller_URL){
					$scope.go(c.data.send_table, c.data.send_sys_id);
				}
			}, 175);
		}
	}

	$scope.go = function(table, sys_id) {

		var parms = {};
		parms.table = table;
		parms.sys_id = sys_id;
		$scope.ignoreLocationChange = true;
		$scope.$emit(eventNames.loadItem, parms);
//		$location.search('table', parms.table).search('sys_id', parms.sys_id).search('spa', '1');
		$rootScope.$broadcast(eventNames.loadItem, parms);
	};

	$scope.$on('spModel.gForm.initialized', function(e, gFormInstance) {
		initForm(gFormInstance);
	});

	$scope.$on('spModel.gForm.env.created', function(e, gFormInstance) {
		initForm(gFormInstance);
	});

	// update the comments or worknotes based on activity stream
	$scope.$on("activity_stream_is_changed", function(event, data) {
		if (g_form && g_form.hasField(data.fieldName)) {
			g_form.setValue(data.fieldName, data.input);
			if (data.fieldToClear != "" && g_form.hasField(data.fieldToClear))
				g_form.setValue(data.fieldToClear, "");
		}
	})

	// Show or hide related lists
	$scope.$watch('data.f._related_lists', function() {
		$scope.data.hideRelatedLists = hideRelatedLists();
	}, true);

	function hideRelatedLists() {
		if (!$scope.data.f._related_lists)
			return true;

		if ($scope.options.hideRelatedLists == true)
			return true;

		if ($scope.data.sys_id == '-1')
			return true;

		// If all related lists are visible=false then hide
		if ($scope.data.f._related_lists.length > 0) {
			for (var i in $scope.data.f._related_lists) {
				var list = $scope.data.f._related_lists[i];
				if (list.visible) {
					return false;
				}
			}
		}
		return true;
	}

	function clearStatus() {
		$scope.status = "";
	}

	if ($scope.data.f.title) {
		$scope.$emit('sp.widget-modal.set-aria-label', $scope.data.f.title);
	}
}

sp_widget.css:
.btn-form-menu {
	vertical-align: inherit;
  padding: inherit;
  background: none;
}

.panel-title {
  word-wrap: break-word;
}

.panel-heading {
  .dropdown-menu {
    a {
      white-space: normal;
    }
  }
}

.sc-field-error-label {
  margin-right: .5em;
  display: inline-block;
  background-color: $sc-field-error-color;
}

.comment {
	font-weight: bold;
	margin-top: 2px;
	margin-bottom: 2px;
}
.mce-panel, .mce-btn {
	background-image: none;
	background-color: #f0f3f4;
}

.action-btn {
  margin-right: 5px;
}

.timeline-container {
   max-height: 50vh;
   height: 100%;
   overflow-y: auto;
}

.panel .panel {
    height: auto !important;
}

.attachment-button {
  .glyphicon-paperclip {
    font-size: 18px;
  }
}

.dropdown {
  .glyphicon-menu-hamburger:focus {
 		outline: thin dotted;
		outline: 5px auto $input-border-focus;
		outline-offset: -2px; 
	}
}

.empty-state-wrapper {
  width: 100%;
  height: 100%;
  align-items: center;
  display: flex;
  flex-direction: column;
  padding: 10vh 20px 20px;

  .empty-state {
    border: 1px solid #e7e9eb;
    border-radius: 10px;
    max-width: 700px;
    padding: 30px 40px 20px;
    position: relative;

    .empty-state-badge {
      top: -36px;
      left: 50%;
      position: absolute;
      height: 72px;
      width: 72px;
      -webkit-align-items: center;
      -ms-flex-align: center;
      align-items: center;
      border-radius: 100%;
      color: #ffffff;
      display: -webkit-flex;
      display: -ms-flexbox;
      display: flex;
      font-size: 40px;
      -webkit-justify-content: center;
      -ms-flex-pack: center;
      justify-content: center;
      margin-left: -36px;
      text-align: center;
    }

    .empty-state-header {
      font-size: 30px;
      text-align: center;
      color: #343d47;
    }

    .empty-state-content {
      ul {
        list-style: disc outside;
        margin: 0 0 10px 0;
        padding: 0 0 0 30px;
      }
    }
  }
}

.text-success-alt {
	background-color: $state-success-text;
}

.text-info-alt {
	background-color: $state-info-text;
}

.sp-cross-scope-msg {
  margin-bottom: 10px;
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: FORM
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: Rob Joy
//------------------------------------------------------------------------------------------------------------------------
// 2.7.0 | 2021-08-23 | raj  | STRY0108629 - DIA- Org Hierarchy Request- Respond Hierarchy Update Bifold
//                                         New widget for this capability
//// form functionality - URL parameter driven
(function(sp, input, data, options, gs) {
  /* "use strict"; -linter issues */
  // populate the 'data' variable
	data.saveChangesMessage = gs.getMessage('Tasker - Modal Save Changes Message');

	data.recordAddedMsg = gs.getMessage("Record Added");
	data.updatedMsg = gs.getMessage("updated_uppercase");
	data.exportPDFMsg = gs.getMessage("Export to PDF");
	data.exportPDFLandMsg = gs.getMessage("Export to PDF (landscape)");

	// *************** Customization Start ***************************
	// RAJ - Removed from Standard form widget as this doesn't work in scoped app
	//data.isAdmin = gs.hasRightsTo('sp/configure.all/execute', null);
	// *************** Customization End ***************************

	data.emptyStateTemplate = options.empty_state_template;
	data.hideRelatedLists = options.hideRelatedLists || false;
	data.disableUIActions = (input || {}).disableUIActions || (options || {}).disableUIActions || false;	
	data.hideRelatedLists = (input || {}).hideRelatedLists || (options || {}).hideRelatedLists || false;
	data.omitHeaderOptions = (input || {}).omitHeaderOptions || (options || {}).omitHeaderOptions;	
	data.omitHeader = (input || {}).omitHeader || (options || {}).omitHeader;	
	data.size = (input || {}).size || (options || {}).size;	
	data.isModal = (input || {}).isModal || (options || {}).isModal;

	// *************** Customization Start ***************************
	// RAJ - added to improve ability to open in a modal
	// rebuild the widget to be a modal
	data.table = (input || {}).table || (options || {}).table || $sp.getParameter("t") || $sp.getParameter("table") || $sp.getParameter("sl_table");
	data.sys_id = (input || {}).sys_id || (options || {}).sys_id || $sp.getParameter("sys_id") || $sp.getParameter("sl_sys_id");
	data.view = (input || {}).view || (options || {}).view || $sp.getParameter("view") || $sp.getParameter("v"); // no default	
	// STRY0108629 - if the Discover Controller URL is set, then override URL parameters
	data.use_Discover_Controller_URL = (input || {}).use_Discover_Controller_URL || (options || {}).use_Discover_Controller_URL;	

	if(data.use_Discover_Controller_URL){
		data.dcu_sys_id = (input || {}).dcu_sys_id || (options || {}).dcu_sys_id || $sp.getParameter("dcu_sys_id");
		data.dcu_table = (input || {}).dcu_table || (options || {}).dcu_table || $sp.getParameter("dcu_table");
		data.dcu_view = (input || {}).dcu_view || (options || {}).dcu_view || $sp.getParameter("dcu_view");	
		data.dcu_ref = (input || {}).dcu_ref || (options || {}).dcu_ref || $sp.getParameter("dcu_ref");
	}

	// *************** Customization end ***************************

// YOU ARE HERE... YOU JUST DECIDED IT IS BETTER TO OVERRIDE DATA TABLE AND LEAVE THE REST OF THE WIDGET USING DATA TABLE AS THE REPLACED DCU
// THEN SET THE SENDER TABLE, SYS_ID, VIEW
// THEN ON ALL PUSHES TO THE URL AND BROADCAST SEND THE SENDER
	if (input) {
		data.use_Discover_Controller_URL = input.use_Discover_Controller_URL;
		data.table = input.table;
		data.sys_id = input.sys_id;
		data.view = input.view;

		// if sys_id changed, reset the dcu_sys_id so it gets reloaded below
		if(data.use_Discover_Controller_URL){
			data.dcu_sys_id = input.sys_id;
		}
		var result = {};
		if (input._fields) {
//			result = $sp.saveRecord(input.table, input.sys_id, input._fields);
//			data.sys_id = result.sys_id;
		}

		if (input.sys_id == '-1'){
			// if here, then need to load empty page saying no more requests
		}

	}

	data.query = $sp.getParameter("query") || options.query || "";
	data.o = $sp.getParameter("o") || options.o || "";
	data.d= $sp.getParameter("d") || options.d|| "";

	data.f = {};

	// NOTE: may want to have something on screen if ANY DCU values are missing
	// At this point all of the options are loaded. 
	// If we are using the Disocver Controller, then swap the table here
	if(data.use_Discover_Controller_URL){	
		// set sys_id to dcu_sys_id to override the URL settings (input setting is reset above)
		data.sys_id = data.dcu_sys_id;
		data.table = data.dcu_table;
		data.view = data.dcu_view;
	}

	if (!data.sys_id && options.sys_id_required != "true")
		data.sys_id = "-1";  // load empty page...

	if (!data.table)
		return;

	// Form widget is not a supported way to view an attachment
	if (data.table == "sys_attachment") {
		data.tableUnsupported = true;
		return;
	}

	// *************** Customization Start ***************************
	// RAJ - Removed from Standard form widget as this doesn't work in scoped app
	//if (!GlideTableDescriptor.isValid(data.table))
	//	return;
	// *************** Customization End ***************************

	// if you are here, check to see if next record has an item
	// STRY0101474 
	if (!data.sys_id || data.sys_id == "-1" || data.sys_id==""){
		var checkNextRec = getNextRecord(null, data.table, data.query, data.o, data.d);
		if(checkNextRec.sys_id != ''){
			data.sys_id = checkNextRec.sys_id;
		} else {
			return;			
		}
	}


	// *************** Customization Start ***************************
	// RAJ - Removed from Standard form widget as this doesn't work in scoped app
	// var rec = $sp.getRecord(data.table, data.sys_id);
	// RAJ - Added below to do what line above did in standard form
	//Possible Disabled for Restricted Tasks
	var rec = new GlideRecordSecure(data.table);

	//STRY0071033: 4. GlideRecord's get() function should be enclosed in an if() statement
	if (rec.get(data.sys_id))
		data.isValid = rec.isValid() || data.sys_id == "-1";
	// *************** Customization End ***************************

	if (!data.isValid)
		return;

	data.table = rec.getRecordClassName();
	// *************** Customization Start ***************************
	// RAJ - Removed from Standard form widget as this doesn't work in scoped app
	// data.tableHierarchy = GlideDBObjectManager.getTables(data.table).toArray().join();
	// RAJ - Added below to do what line above did in standard form
	var table = new GlideTableHierarchy(data.table);
	data.tableHierarchy = table.getTables();
	// *************** Customization End ***************************

	data.canWrite = rec.canWrite();
	var hasRecordAccess = data.sys_id == "-1" ? rec.canCreate() : data.canWrite;
	// *************** Customization Start ***************************
	// RAJ - Removed from Standard form widget as this doesn't work in scoped app
	//	data.canAttach = hasRecordAccess && gs.hasRole(gs.getProperty('glide.attachment.role')) && !GlideTableDescriptor.get(data.table).getED().getBooleanAttribute("no_attachment");
	// *************** Customization End ***************************
	//	data.f = $sp.getForm(data.table, data.sys_id, data.query, data.view, isPopup);
	data.f = $sp.getForm(data.table, data.sys_id, '', data.view);

	// *************** Customization Start ***************************
	// RAJ - Removed from Standard form widget as this doesn't work in scoped app
	// PRB1335036: show appropriate message when record is in cross app scope
	//data.f.outOfScope = !rec.isInSelectedScope();
	// Populate scope labels only when needed
	//if (data.f.outOfScope) {
	//	data.f.recordScopeLabel = gs.getScopeLabelByRecordId(rec.getUniqueValue());
	//	data.f.currentScopeLabel = gs.getCurrentApplicationName();
	//}
	// *************** Customization End ***************************

	// the data is now loaded for this form, get the data for the controller send
	if(data.use_Discover_Controller_URL){
		data.send_sys_id = -1;
		if(data.dcu_ref){
			data.send_table = rec[data.dcu_ref].getRefRecord().getTableName();
			if(rec.getValue(data.dcu_ref)){
				data.send_sys_id = rec.getValue(data.dcu_ref);				
			}  // NOTE: may want to have something on screen if the reference record is not set

			// we aren't doing much with sys id here
			data.send_view = data.view;

		}
	} // NOTE: may want to set something on screen to say dcu_ref was expected, but not provided
	data.nextRec = getNextRecord(rec, data.table, data.query, data.o, data.d);
	data.prevRec = getPrevRecord(rec, data.table, data.query, data.o, data.d);

	// Activity formatter is hardcoded to set specific options
	for (var f in data.f._formatters) {
		var fm = data.f._formatters[f];
		if (fm.formatter == "activity.xml") {
			fm.hardcoded = true;
			fm.widgetInstance = $sp.getWidget('widget-ticket-conversation',
																{table: data.table,
																 sys_id: data.sys_id,
																 includeExtended: true,
																 hideAttachmentBtn: true,
																 title: "${Activity}",
																 use_dynamic_placeholder: true,
																 btnLabel: "${Post}"});
		} else if(fm.formatter == "com_glideapp_servicecatalog_veditor" || fm.formatter == "com_glideapp_questionset_default_question_editor") {
			var qsConfig = $sp.getValue('quick_start_config');
			if (qsConfig)
				qsConfig = JSON.parse(qsConfig)[0];
			fm.widgetInstance = $sp.getWidget(fm.widget, {table: data.table,
														sys_id: data.sys_id,
														readonly_variable_editor: qsConfig ? qsConfig.readonly_variable_editor : 'false'});
		} else
			fm.widgetInstance = $sp.getWidget(fm.widget, data);
	}

	function getNextRecord (rec, table, query, o, d){
		var recReturn = {};
		recReturn.sys_id = '';
		recReturn.displayValue = '';
		var nextRec = new GlideRecordSecure(data.table);

		var fullQuery = query;
		if(d=='desc'){
			nextRec.orderByDesc(o);
			// STRY0101474
			if(rec!=null){
				fullQuery = query + '^' + o + '<' + rec.getValue(o);	
			} else {
				fullQuery = query;
			}

		} else {
			nextRec.orderBy(o);
			if(rec!=null){
				fullQuery = query + '^' + o + '>' + rec.getValue(o);
			} else {
				fullQuery = query;
			}				
		}

		nextRec.addEncodedQuery(fullQuery);
		nextRec.query();
		if(nextRec.next()){
			recReturn.displayValue = nextRec.getDisplayValue();
			recReturn.sys_id = nextRec.getUniqueValue();
		}
		return recReturn;
	}
	// previews rec, changes the order and calls next rec
	function getPrevRecord(rec, table, query, o, d){
		var prevRec;
		if(d=='desc'){
			prevRec = getNextRecord(rec, table, query, o, 'asc');
		} else {
			prevRec = getNextRecord(rec, table, query, o, 'desc');
		}
		return prevRec;
	}

})($sp, input, data, options, gs);
